const items = [
  { name: 'Iron Sword', type: 'weapon', price: 100 },
  { name: 'Steel Shield', type: 'armor', price: 150 },
  { name: 'Health Potion', type: 'consumable', price: 25 },
  { name: 'Mana Potion', type: 'consumable', price: 30 },
  { name: 'Dragon Scale', type: 'material', price: 500 },
];

function getInventory() { return items; }

function getItemByName(name) {
  return items.find(i => i.name.toLowerCase() === name.toLowerCase()) || null;
}

function getTotalValue() {
  return items.reduce((sum, item) => sum + item.price, 0);
}

module.exports = { getInventory, getItemByName, getTotalValue };

