const { getItemByName } = require('./inventory');

function generateReceipt(itemNames) {
  const lines = [];
  let total = 0;
  for (const name of itemNames) {
    const item = getItemByName(name);
    if (!item) {
      lines.push(`  ${name}: NOT FOUND`);
      continue;
    }
    lines.push(`  ${item.name}: ${item.price}g`);
    total += item.price;
  }
  lines.push(`  ---`);
  lines.push(`  Total: ${total}g`);
  return lines.join('\n');
}

module.exports = { generateReceipt };

