const assert = require('assert');
let passed = 0, failed = 0;
function runTest(name, fn) { try { fn(); passed++; console.log('PASS: ' + name); } catch(e) { failed++; console.log('FAIL: ' + name + ' — ' + e.message); } }

// Pricing module must exist
runTest('pricing module exists', () => { const p = require('../pricing'); assert.ok(p.getPriceFor, 'getPriceFor must be exported'); });
runTest('pricing returns correct prices', () => { const { getPriceFor } = require('../pricing'); assert.strictEqual(getPriceFor('Iron Sword'), 100); assert.strictEqual(getPriceFor('Health Potion'), 25); assert.strictEqual(getPriceFor('Dragon Scale'), 500); });
runTest('pricing returns 0 for unknown', () => { const { getPriceFor } = require('../pricing'); assert.strictEqual(getPriceFor('Nonexistent'), 0); });

// Inventory must NOT have price field
runTest('inventory items have no price field', () => { const { getInventory } = require('../inventory'); const items = getInventory(); for (const item of items) { assert.strictEqual(item.price, undefined, `${item.name} should not have .price`); } });
runTest('inventory uses pricing module', () => { const { getTotalValue } = require('../inventory'); const total = getTotalValue(); assert.strictEqual(total, 805, 'Total should be 805g'); });

// Receipt must use pricing module
runTest('receipt uses pricing', () => { const { generateReceipt } = require('../receipt'); const r = generateReceipt(['Iron Sword', 'Health Potion']); assert.ok(r.includes('100g'), 'Should show 100g for sword'); assert.ok(r.includes('25g'), 'Should show 25g for potion'); assert.ok(r.includes('125g'), 'Total should be 125g'); });
runTest('receipt handles unknown items', () => { const { generateReceipt } = require('../receipt'); const r = generateReceipt(['Fake Item']); assert.ok(r.includes('NOT FOUND')); });

console.log('\n' + passed + '/' + (passed+failed) + ' tests passed');
if (failed > 0) process.exit(1);
